// 1. Sadə Generics ilə funksiya
function identity<T>(value: T): T {
  return value;
}
const num = identity<number>(42); // T = number
console.log(num); // Çıxış: 42
const str = identity<string>("Hello"); // T = string
console.log(str); // Çıxış: Hello

// 2. Generics ilə məhdudiyyətlər
function printLength<T extends { length: number }>(item: T): number {
  return item.length;
}
console.log(printLength<string>("Test")); // Çıxış: 4
console.log(printLength<string[]>(["a", "b"])); // Çıxış: 2
// console.log(printLength<number>(42)); // Səhv: number-ın length xüsusiyyəti yoxdur

// 3. Generics ilə interfeyslər
interface Box<T> {
  content: T;
  id: string;
}
const stringBox: Box<string> = { content: "Book", id: "B001" };
const numberBox: Box<number> = { content: 100, id: "B002" };
console.log(stringBox); // Çıxış: { content: "Book", id: "B001" }
console.log(numberBox); // Çıxış: { content: 100, id: "B002" }

// 4. Generics ilə siniflər
class Store<T> {
  items: T[] = [];
  add(item: T): void {
    this.items.push(item);
  }
  getAll(): T[] {
    return this.items;
  }
}
const numberStore = new Store<number>();
numberStore.add(1);
numberStore.add(2);
console.log(numberStore.getAll()); // Çıxış: [1, 2]
const stringStore = new Store<string>();
stringStore.add("Apple");
console.log(stringStore.getAll()); // Çıxış: ["Apple"]

// 5. Çoxsaylı Generic tiplər
function pair<T, U>(first: T, second: U): [T, U] {
  return [first, second];
}
const myPair = pair<string, number>("Age", 25);
console.log(myPair); // Çıxış: ["Age", 25]

// 6. Default Generic tiplər
function wrap<T = string>(value: T): { value: T } {
  return { value };
}
const wrappedString = wrap("Test"); // T avtomatik string olur
const wrappedNumber = wrap<number>(42);
console.log(wrappedString); // Çıxış: { value: "Test" }
console.log(wrappedNumber); // Çıxış: { value: 42 }

// 7. Generics ilə union tipləri
type AllowedType = string | number;
function restrict<T extends AllowedType>(value: T): T {
  return value;
}
console.log(restrict("Hello")); // Çıxış: Hello
console.log(restrict(123)); // Çıxış: 123
// console.log(restrict(true)); // Səhv: boolean AllowedType-a uyğun deyil

// Sadə mağaza sistemi
interface Product<T> {
  id: string;
  data: T;
}
class ProductStore<T> {
  products: Product<T>[] = [];
  add(id: string, data: T): void {
    this.products.push({ id, data });
  }
  getById(id: string): Product<T> | undefined {
    return this.products.find(p => p.id === id);
  }
}
const store = new ProductStore<string>();
store.add("P001", "Laptop");
store.add("P002", "Mouse");
console.log(store.getById("P001")); // Çıxış: { id: "P001", data: "Laptop" }

const numberStore = new ProductStore<number>();
numberStore.add("P003", 999);
console.log(numberStore.getById("P003")); // Çıxış: { id: "P003", data: 999 }

// Generic funksiya ilə məhsul yoxlaması
function checkProduct<T>(product: Product<T>): string {
  return `Product ID: ${product.id}, Data: ${product.data}`;
}
const laptopProduct: Product<string> = { id: "P001", data: "Laptop" };
console.log(checkProduct(laptopProduct)); // Çıxış: Product ID: P001, Data: Laptop

